example.code:
# Appropriate use of different scopes
@pytest.fixture(scope="function")  # Default — fresh state per test
def fresh_user():
    return User(id=str(uuid4()), email=f"u-{uuid4().hex[:8]}@test.com")

@pytest.fixture(scope="session")   # OK — read-only, expensive setup
def docker_postgres():
    container = start_postgres_container()
    yield container
    container.stop()

@pytest.fixture(scope="module")    # Risky — only if state truly immutable
def read_only_config():
    return load_config("tests/fixtures/config.json")

@pytest.fixture
def temp_directory():
    temp_dir = Path(tempfile.mkdtemp())
    yield temp_dir
    shutil.rmtree(temp_dir)  # Always runs, even on test failure

@pytest.fixture
def db_session(session_factory):
    session = session_factory()
    session.begin_nested()  # Savepoint
    yield session
    session.rollback()      # Roll back to savepoint
    session.close()
